public class Solution {
    public static int processOrder(Object products_list, Object quantities_list) {
        Map<String, Integer> product_prices = new HashMap<>();
        product_prices.put("Laptop", 1000);
        product_prices.put("Headphones", 500);
        product_prices.put("Mouse", 50);
        product_prices.put("Charger", 30);

        Map<String, Integer> discounts = new HashMap<>();
        discounts.put("Laptop", 100);
        discounts.put("Headphones", 50);

        if (!(products_list instanceof List) || !(quantities_list instanceof List)) {
            throw new IllegalArgumentException("products_list and quantities_list must be lists");
        }

        List<?> products = (List<?>) products_list;
        List<?> quantities = (List<?>) quantities_list;

        if (products.size() != quantities.size()) {
            throw new IllegalArgumentException("products_list and quantities_list must have the same length");
        }

        for (Object q : quantities) {
            if (!(q instanceof Integer)) {
                throw new IllegalArgumentException("quantities must be integers");
            }
            if ((Integer) q < 0) {
                throw new IllegalArgumentException("quantities must be non-negative");
            }
        }

        int total_price = 0;
        for (int i = 0; i < products.size(); i++) {
            String product = (String) products.get(i);
            int quantity = (Integer) quantities.get(i);
            if (product_prices.containsKey(product)) {
                int price = product_prices.get(product);
                int discount = discounts.getOrDefault(product, 0);
                total_price += (price - discount) * quantity;
            }
        }
        return total_price;
    }
}

