        if (!Pattern.matches("[0-9A-F]{12}", device_id)) {
            throw new IllegalArgumentException("invalid device_id");
        }

        Object fwObj = info.get("firmware_version");
        if (!(fwObj instanceof String)) {
            throw new IllegalArgumentException("firmware_version must be a string");
        }
        String fw = (String) fwObj;
        Matcher m = Pattern.compile("v(\\d{1,3})\\.(\\d{1,3})\\.(\\d{1,3})").matcher(fw);
        if (!m.matches()) {
            throw new IllegalArgumentException("invalid firmware_version");
        }
        int major = Integer.parseInt(m.group(1));
        int minor = Integer.parseInt(m.group(2));
        int patch = Integer.parseInt(m.group(3));
        if (major < 0 || major > 999 || minor < 0 || minor > 999 || patch < 0 || patch > 999) {
            throw new IllegalArgumentException("invalid firmware_version");
        }

        Object enabledObj = info.get("enabled");
        if (!(enabledObj instanceof Boolean)) {
            throw new IllegalArgumentException("enabled must be a bool");
        }

        if (info.containsKey("tags")) {
            Object tagsObj = info.get("tags");
            if (!(tagsObj instanceof List)) {
                throw new IllegalArgumentException("tags must be a list");
            }
