            for (Object t : tags) {
                if (!(t instanceof String)) {
                    throw new IllegalArgumentException("tag must be a string");
                }
                String tag = (String) t;
                if (tag.length() < 1 || tag.length() > 20) {
                    throw new IllegalArgumentException("tag length out of range");
                }
                if (!Pattern.matches("[A-Za-z0-9_]+", tag)) {
                    throw new IllegalArgumentException("invalid tag");
                }
            }
        }

        return String.format("Registered: %s", device_id);
    }
