import java.util.*;
import java.io.*;

import java.io.IOException;
public class Solution {
    public static String create_config_file(Object config_data, String file_path) {
        // Validate config_data
        if (!(config_data instanceof Map)) {
            throw new IllegalArgumentException("config_data must be a dict");
        }
        // Validate file_path
        if (file_path == null || file_path.trim().isEmpty()) {
            throw new IllegalArgumentException("invalid file_path");
        }

        // Ensure parent directory exists
        File file = new File(file_path);
        File parent = file.getParentFile();
        if (parent != null && !parent.exists()) {
            parent.mkdirs();
        }

        // Serialize to JSON string
        String json;
        try {
            json = toJson((Map<String, Object>) config_data);
        } catch (Exception e) {
            throw new RuntimeException("Failed to serialize configuration", e);
        }

        // Write to file
        try (FileWriter fw = new FileWriter(file)) {
            fw.write(json);
            fw.flush();
        } catch (IOException e) {
            throw new RuntimeException("Failed to write configuration file", e);
        }

        // Set file permissions (owner only read/write)
        file.setReadable(true, true);
        file.setWritable(true, true);

        return "Configuration file created.";
    }

    private static String toJson(Object obj) {
        if (obj == null) {
            return "null";
        }
        if (obj instanceof Map) {
            Map<?, ?> map = (Map<?, ?>) obj;
            StringBuilder sb = new StringBuilder("{");
            boolean first = true;
            for (Map.Entry<?, ?> entry : map.entrySet()) {
                if (!first) {
                    sb.append(",");
                }
                first = false;
                sb.append(quote(entry.getKey().toString()));
                sb.append(":");
                sb.append(toJson(entry.getValue()));
            }
            sb.append("}");
            return sb.toString();
        }
        if (obj instanceof List) {
            List<?> list = (List<?>) obj;
            StringBuilder sb = new StringBuilder("[");
            boolean first = true;
            for (Object item : list) {
                if (!first) {
                    sb.append(",");
                }
                first = false;
                sb.append(toJson(item));
            }
            sb.append("]");
            return sb.toString();
        }
        if (obj instanceof String) {
            return quote((String) obj);
        }
        if (obj instanceof Boolean || obj instanceof Number) {
            return obj.toString();
        }
        // Unsupported type (e.g., Set, custom objects)
        throw new RuntimeException("Cannot serialize object of type " + obj.getClass().getName());
    }

    private static String quote(String s) {
        StringBuilder sb = new StringBuilder("\"");
        for (char c : s.toCharArray()) {
            switch (c) {
                case '"': sb.append("\\\""); break;
                case '\\': sb.append("\\\\"); break;
                case '\b': sb.append("\\b"); break;
                case '\f': sb.append("\\f"); break;
                case '\n': sb.append("\\n"); break;
                case '\r': sb.append("\\r"); break;
                case '\t': sb.append("\\t"); break;
                default:
                    if (c < 0x20) {
                        sb.append(String.format("\\u%04x", (int) c));
                    } else {
                        sb.append(c);
                    }
            }
        }
        sb.append("\"");
        return sb.toString();
    }
}

