        menu.put("Burger", 10);
        menu.put("Fries", 4);
        menu.put("Soda", 1);
        menu.put("Salad", 7);

        if (!(items_ordered instanceof List)) {
            throw new IllegalArgumentException("items_ordered must be a list");
        }
        if (!(tax_rate instanceof Number)) {
            throw new IllegalArgumentException("tax_rate must be a number");
        }
