            String key = ((String) item).substring(0, 1).toUpperCase() + ((String) item).substring(1).toLowerCase();
            if (!menu.containsKey(key)) {
                throw new IllegalArgumentException("unknown menu item");
            }
            subtotal += ((Number) menu.get(key)).doubleValue();
        }

        double total_cost = subtotal + subtotal * taxRateValue;
        return Math.round(total_cost * 100.0) / 100.0;
    }
