public class Solution {
    public static Map<String, Object> load_plugin_config(String config_string) {
        if (config_string == null) throw new IllegalArgumentException("config_string cannot be null");
        byte[] decoded;
        try {
            decoded = Base64.getDecoder().decode(config_string);
        } catch (IllegalArgumentException e) {
            throw new IllegalArgumentException("Invalid base64", e);
        }
        String text = new String(decoded, StandardCharsets.UTF_8);
        text = text.trim();
        if (text.isEmpty() || text.charAt(0) != '{') {
            throw new IllegalArgumentException("plugin configuration must be a JSON object");
        }
        Object parsed = parseJson(text);
        if (!(parsed instanceof Map)) {
            throw new IllegalArgumentException("Top-level must be a JSON object");
        }
        @SuppressWarnings("unchecked")
        Map<String, Object> map = (Map<String, Object>) parsed;
        return map;
    }

    private static Object parseJson(String json) {
        int[] i = {0};
        Object val = parseValue(json, i);
        skipWhitespace(json, i);
        if (i[0] != json.length()) {
            throw new IllegalArgumentException("Unexpected characters after JSON");
        }
        return val;
    }

    private static void skipWhitespace(String json, int[] i) {
        while (i[0] < json.length() && Character.isWhitespace(json.charAt(i[0]))) i[0]++;
    }

    private static Object parseValue(String json, int[] i) {
        skipWhitespace(json, i);
        if (i[0] >= json.length()) throw new IllegalArgumentException("Unexpected end of JSON input");
        char c = json.charAt(i[0]);
        if (c == '{') return parseObject(json, i);
        if (c == '[') return parseArray(json, i);
        if (c == '"') return parseString(json, i);
        if (c == 't' || c == 'f') return parseBoolean(json, i);
        if (c == 'n') {
            parseNull(json, i);
            return null;
        }
        if (c == '-' || (c >= '0' && c <= '9')) return parseNumber(json, i);
        throw new IllegalArgumentException("Unexpected character: " + c);
    }

    private static Map<String, Object> parseObject(String json, int[] i) {
        i[0]++; // skip '{'
        Map<String, Object> map = new HashMap<>();
        skipWhitespace(json, i);
        if (i[0] < json.length() && json.charAt(i[0]) == '}') {
            i[0]++;
            return map;
        }
        while (true) {
            skipWhitespace(json, i);
            if (json.charAt(i[0]) != '"') throw new IllegalArgumentException("Expected string key");
            String key = parseString(json, i);
            skipWhitespace(json, i);
            if (json.charAt(i[0]) != ':') throw new IllegalArgumentException("Expected ':'");
            i[0]++;
            Object value = parseValue(json, i);
            map.put(key, value);
            skipWhitespace(json, i);
            char delim = json.charAt(i[0]);
            if (delim == '}') {
                i[0]++;
                return map;
            } else if (delim == ',') {
                i[0]++;
            } else {
                throw new IllegalArgumentException("Expected ',' or '}' in object");
            }
        }
    }

    private static List<Object> parseArray(String json, int[] i) {
        i[0]++; // skip '['
        List<Object> list = new ArrayList<>();
        skipWhitespace(json, i);
        if (i[0] < json.length() && json.charAt(i[0]) == ']') {
            i[0]++;
            return list;
        }
        while (true) {
            Object value = parseValue(json, i);
            list.add(value);
            skipWhitespace(json, i);
            char delim = json.charAt(i[0]);
            if (delim == ']') {
                i[0]++;
                return list;
            } else if (delim == ',') {
                i[0]++;
            } else {
                throw new IllegalArgumentException("Expected ',' or ']' in array");
            }
        }
    }

    private static String parseString(String json, int[] i) {
        i[0]++; // skip opening quote
        StringBuilder sb = new StringBuilder();
        while (i[0] < json.length()) {
            char c = json.charAt(i[0]);
            if (c == '"') {
                i[0]++;
                return sb.toString();
            }
            if (c == '\\') {
                i[0]++;
                if (i[0] >= json.length()) throw new IllegalArgumentException("Escape at end of string");
                char escaped = json.charAt(i[0]);
                switch (escaped) {
                    case '"': sb.append('"'); break;
                    case '\\': sb.append('\\'); break;
                    case '/': sb.append('/'); break;
                    case 'b': sb.append('\b'); break;
                    case 'f': sb.append('\f'); break;
                    case 'n': sb.append('\n'); break;
                    case 'r': sb.append('\r'); break;
                    case 't': sb.append('\t'); break;
                    case 'u':
                        // skip Unicode escapes for simplicity — not needed in test
                        throw new IllegalArgumentException("Unicode escapes not supported");
                    default:
                        throw new IllegalArgumentException("Invalid escape: \\" + escaped);
                }
                i[0]++;
            } else {
                sb.append(c);
                i[0]++;
            }
        }
        throw new IllegalArgumentException("Unterminated string");
    }

    private static boolean parseBoolean(String json, int[] i) {
        if (json.startsWith("true", i[0])) {
            i[0] += 4;
            return true;
        }
        if (json.startsWith("false", i[0])) {
            i[0] += 5;
            return false;
        }
        throw new IllegalArgumentException("Invalid boolean literal");
    }

    private static void parseNull(String json, int[] i) {
        if (json.startsWith("null", i[0])) {
            i[0] += 4;
        } else {
            throw new IllegalArgumentException("Invalid null literal");
        }
    }

    private static Number parseNumber(String json, int[] i) {
        int start = i[0];
        if (json.charAt(i[0]) == '-') i[0]++;
        if (i[0] >= json.length() || !Character.isDigit(json.charAt(i[0]))) {
            throw new IllegalArgumentException("Invalid number");
        }
        while (i[0] < json.length() && Character.isDigit(json.charAt(i[0]))) i[0]++;
        if (i[0] < json.length() && json.charAt(i[0]) == '.') {
            i[0]++;
            while (i[0] < json.length() && Character.isDigit(json.charAt(i[0]))) i[0]++;
