            if (i[0] < json.length() && (json.charAt(i[0]) == '+' || json.charAt(i[0]) == '-')) i[0]++;
            while (i[0] < json.length() && Character.isDigit(json.charAt(i[0]))) i[0]++;
        }
        String numStr = json.substring(start, i[0]);
        if (numStr.contains(".") || numStr.toLowerCase().contains("e")) {
            return Double.parseDouble(numStr);
        } else {
            return Long.parseLong(numStr);
        }
    }

