import java.util.Base64;

public class Solution {
    public static Map<String, Object> decodeAuthToken(String tokenString) {
        if (tokenString == null) {
            throw new IllegalArgumentException("tokenString must be a string");
        }
        byte[] decoded;
        try {
            decoded = Base64.getDecoder().decode(tokenString);
        } catch (IllegalArgumentException e) {
            throw new IllegalArgumentException("invalid token encoding", e);
        }
        String text;
        try {
            text = new String(decoded, StandardCharsets.UTF_8);
        } catch (Exception e) {
            throw new IllegalArgumentException("invalid token text", e);
        }

        // Parse the JSON-like text with support for single quotes
        Object result = parseValue(text.trim());
        if (result instanceof Map) {
            @SuppressWarnings("unchecked")
            Map<String, Object> map = (Map<String, Object>) result;
            return map;
        } else {
            throw new IllegalArgumentException("token must be a JSON object");
        }
    }

    private static Object parseValue(String json) {
        json = json.trim();
        if (json.isEmpty()) {
            throw new IllegalArgumentException("empty JSON");
        }
        char first = json.charAt(0);
        if (first == '{') {
            return parseObject(json);
        } else if (first == '[') {
            return parseArray(json);
        } else if (first == '"' || first == '\'') {
            return parseString(json);
        } else if (first == 't' || first == 'f') {
            if (json.startsWith("true")) {
                return Boolean.TRUE;
            } else if (json.startsWith("false")) {
                return Boolean.FALSE;
            } else {
                throw new IllegalArgumentException("invalid boolean");
            }
        } else if (first == 'n') {
            if (json.startsWith("null")) {
                return null;
            } else {
                throw new IllegalArgumentException("invalid null");
            }
        } else if (first == '-' || Character.isDigit(first)) {
            return parseNumber(json);
        } else {
            throw new IllegalArgumentException("unexpected character: " + first);
        }
    }

    private static Map<String, Object> parseObject(String json) {
        Map<String, Object> map = new LinkedHashMap<>();
        json = json.trim();
        if (!json.startsWith("{") || !json.endsWith("}")) {
            throw new IllegalArgumentException("invalid object");
        }
        String inner = json.substring(1, json.length() - 1).trim();
        if (inner.isEmpty()) {
            return map;
        }
        // Split by commas, respecting nested structures and quotes
        List<String> pairs = splitTopLevel(inner, ',');
        for (String pair : pairs) {
            List<String> keyValue = splitTopLevel(pair, ':');
            if (keyValue.size() != 2) {
                throw new IllegalArgumentException("invalid key-value pair");
            }
            String key = parseString(keyValue.get(0).trim()).toString();
            Object value = parseValue(keyValue.get(1).trim());
            map.put(key, value);
        }
        return map;
    }

    private static List<Object> parseArray(String json) {
        List<Object> list = new ArrayList<>();
        json = json.trim();
        if (!json.startsWith("[") || !json.endsWith("]")) {
            throw new IllegalArgumentException("invalid array");
        }
        String inner = json.substring(1, json.length() - 1).trim();
        if (inner.isEmpty()) {
            return list;
        }
        List<String> elements = splitTopLevel(inner, ',');
        for (String elem : elements) {
            list.add(parseValue(elem.trim()));
        }
        return list;
    }

    private static String parseString(String json) {
        json = json.trim();
        char quote = json.charAt(0);
        if (quote != '"' && quote != '\'') {
            throw new IllegalArgumentException("string must start with quote");
        }
        StringBuilder sb = new StringBuilder();
        int i = 1;
        while (i < json.length()) {
            char c = json.charAt(i);
            if (c == '\\') {
                if (i + 1 < json.length()) {
                    char next = json.charAt(i + 1);
                    switch (next) {
                        case '"':
                        case '\'':
                        case '\\':
                        case '/':
                            sb.append(next);
                            i += 2;
                            break;
                        case 'b':
                            sb.append('\b');
                            i += 2;
                            break;
                        case 'f':
                            sb.append('\f');
                            i += 2;
                            break;
                        case 'n':
                            sb.append('\n');
                            i += 2;
                            break;
                        case 'r':
                            sb.append('\r');
                            i += 2;
                            break;
                        case 't':
                            sb.append('\t');
                            i += 2;
                            break;
                        case 'u':
                            if (i + 5 < json.length()) {
                                String hex = json.substring(i + 2, i + 6);
                                sb.append((char) Integer.parseInt(hex, 16));
                                i += 6;
                            } else {
                                throw new IllegalArgumentException("Invalid unicode escape");
                            }
                            break;
                        default:
                            throw new IllegalArgumentException("Invalid escape character: " + next);
                    }
                } else {
                    throw new IllegalArgumentException("Unexpected end of string");
                }
            } else if (c == quote) {
                return sb.toString();
            } else {
                sb.append(c);
                i++;
            }
        }
        throw new IllegalArgumentException("Unterminated string");
    }

    private static Number parseNumber(String json) {
        json = json.trim();
        int end = 0;
        boolean isDouble = false;
        while (end < json.length()) {
            char c = json.charAt(end);
            if (Character.isDigit(c) || c == '-' || c == '+' || c == '.' || c == 'e' || c == 'E') {
                if (c == '.' || c == 'e' || c == 'E') {
                    isDouble = true;
                }
                end++;
            } else {
                break;
            }
        }
        String numStr = json.substring(0, end);
        if (isDouble) {
            return Double.parseDouble(numStr);
        } else {
            long val = Long.parseLong(numStr);
            if (val >= Integer.MIN_VALUE && val <= Integer.MAX_VALUE) {
                return (int) val;
            }
            return val;
        }
    }

    private static List<String> splitTopLevel(String str, char delimiter) {
        List<String> parts = new ArrayList<>();
        int depth = 0;
        boolean inString = false;
        char stringChar = 0;
        StringBuilder current = new StringBuilder();
        for (int i = 0; i < str.length(); i++) {
            char c = str.charAt(i);
            if (inString) {
                if (c == '\\') {
                    current.append(c);
                    if (i + 1 < str.length()) {
                        current.append(str.charAt(i + 1));
                        i++;
                    }
                } else if (c == stringChar) {
                    inString = false;
                    current.append(c);
                } else {
                    current.append(c);
                }
            } else {
                if (c == '\'' || c == '"') {
                    inString = true;
                    stringChar = c;
                    current.append(c);
                } else if (c == '{' || c == '[') {
                    depth++;
                    current.append(c);
                } else if (c == '}' || c == ']') {
                    depth--;
                    current.append(c);
                } else if (c == delimiter && depth == 0) {
                    parts.add(current.toString());
                    current.setLength(0);
                } else {
                    current.append(c);
                }
            }
        }
        if (current.length() > 0) {
            parts.add(current.toString());
        }
        return parts;
    }
}

