    private static boolean isValidJsonObject(String s) {
        int i = 0;
        int len = s.length();
        while (i < len && Character.isWhitespace(s.charAt(i))) i++;
        if (i >= len || s.charAt(i) != '{') return false;

        java.util.Deque<Character> stack = new java.util.ArrayDeque<>();
        stack.push('{');
        i++;

        while (i < len) {
            char c = s.charAt(i);
            if (c == '{' || c == '[') {
                stack.push(c);
                i++;
            } else if (c == '}') {
                if (stack.isEmpty() || stack.pop() != '{') return false;
                i++;
            } else if (c == ']') {
                if (stack.isEmpty() || stack.pop() != '[') return false;
                i++;
            } else if (c == '"') {
                i++;
                while (i < len) {
                    char ch = s.charAt(i);
                    if (ch == '\\') {
                        i += 2;
                    } else if (ch == '"') {
                        i++;
                        break;
                    } else {
                        i++;
                    }
                }
                if (i > len) return false;
            } else if (c == 't' && s.startsWith("true", i)) {
                i += 4;
            } else if (c == 'f' && s.startsWith("false", i)) {
                i += 5;
            } else if (c == 'n' && s.startsWith("null", i)) {
                i += 4;
            } else if (Character.isDigit(c) || c == '-') {
                i++;
                while (i < len && (Character.isDigit(s.charAt(i)) || s.charAt(i) == '.' ||
                                   s.charAt(i) == 'e' || s.charAt(i) == 'E' ||
                                   s.charAt(i) == '+' || s.charAt(i) == '-')) {
