public class Solution {
    public static Object evaluate_expression(String expression) {
        if (expression == null) {
            throw new IllegalArgumentException("expression must be a string");
        }

        // Check for invalid characters
        Set<Character> allowed = new HashSet<>();
        for (char c : "0123456789+-*/() ".toCharArray()) {
            allowed.add(c);
        }

        if (expression.trim().isEmpty()) {
            throw new IllegalArgumentException("empty expression");
        }

        for (char ch : expression.toCharArray()) {
            if (!allowed.contains(ch)) {
                throw new IllegalArgumentException("invalid character");
            }
        }

        // Tokenize and evaluate
        try {
            List<Token> tokens = tokenize(expression);
            Parser parser = new Parser(tokens);
            int result = parser.parseExpression();
            if (parser.currentToken.type != TokenType.END) {
                throw new IllegalArgumentException("invalid expression");
            }
            return result;
        } catch (ArithmeticException e) {
            throw e;
        } catch (IllegalArgumentException e) {
            throw e;
        } catch (Exception e) {
            throw new IllegalArgumentException("invalid expression", e);
        }
    }

    // Token types
    private enum TokenType { NUMBER, PLUS, MINUS, TIMES, DIVIDE, LPAREN, RPAREN, END }

    private static class Token {
        TokenType type;
        int value; // only for NUMBER

        Token(TokenType type) { this.type = type; }
        Token(TokenType type, int value) { this.type = type; this.value = value; }
    }

    private static List<Token> tokenize(String expr) {
        List<Token> tokens = new ArrayList<>();
        int i = 0;
        int n = expr.length();
        while (i < n) {
            char c = expr.charAt(i);
            if (c == ' ') {
                i++;
                continue;
            }
            if (c >= '0' && c <= '9') {
                int num = 0;
                while (i < n && expr.charAt(i) >= '0' && expr.charAt(i) <= '9') {
                    num = num * 10 + (expr.charAt(i) - '0');
                    i++;
                }
                tokens.add(new Token(TokenType.NUMBER, num));
            } else {
                switch (c) {
                    case '+': tokens.add(new Token(TokenType.PLUS)); break;
                    case '-': tokens.add(new Token(TokenType.MINUS)); break;
                    case '*': tokens.add(new Token(TokenType.TIMES)); break;
                    case '/': tokens.add(new Token(TokenType.DIVIDE)); break;
                    case '(': tokens.add(new Token(TokenType.LPAREN)); break;
                    case ')': tokens.add(new Token(TokenType.RPAREN)); break;
                    default: throw new IllegalArgumentException("invalid character: " + c);
                }
                i++;
            }
        }
        tokens.add(new Token(TokenType.END));
        return tokens;
    }

    private static class Parser {
        List<Token> tokens;
        int pos;
        Token currentToken;

        Parser(List<Token> tokens) {
            this.tokens = tokens;
            this.pos = 0;
            this.currentToken = tokens.get(0);
        }

        void eat(TokenType type) {
            if (currentToken.type == type) {
                pos++;
                if (pos < tokens.size()) {
                    currentToken = tokens.get(pos);
                } else {
                    currentToken = new Token(TokenType.END);
                }
            } else {
                throw new IllegalArgumentException("unexpected token: expected " + type + " but got " + currentToken.type);
            }
        }

        int parseExpression() {
            int result = parseTerm();
            while (currentToken.type == TokenType.PLUS || currentToken.type == TokenType.MINUS) {
                if (currentToken.type == TokenType.PLUS) {
                    eat(TokenType.PLUS);
                    result += parseTerm();
                } else if (currentToken.type == TokenType.MINUS) {
                    eat(TokenType.MINUS);
                    result -= parseTerm();
                }
            }
            return result;
        }

        int parseTerm() {
            int result = parseFactor();
            while (currentToken.type == TokenType.TIMES || currentToken.type == TokenType.DIVIDE) {
                if (currentToken.type == TokenType.TIMES) {
                    eat(TokenType.TIMES);
                    result *= parseFactor();
                } else if (currentToken.type == TokenType.DIVIDE) {
                    eat(TokenType.DIVIDE);
                    int divisor = parseFactor();
                    if (divisor == 0) {
                        throw new ArithmeticException("division by zero");
                    }
                    result /= divisor;
                }
            }
            return result;
        }

        int parseFactor() {
            // handle unary minus
            if (currentToken.type == TokenType.MINUS) {
                eat(TokenType.MINUS);
                int val = parseFactor();
                return -val;
            }
            if (currentToken.type == TokenType.NUMBER) {
                int val = currentToken.value;
                eat(TokenType.NUMBER);
                return val;
            }
            if (currentToken.type == TokenType.LPAREN) {
                eat(TokenType.LPAREN);
                int val = parseExpression();
                eat(TokenType.RPAREN);
                return val;
            }
            throw new IllegalArgumentException("unexpected token: " + currentToken.type);
        }
    }
