    public static String evaluate_expressions(String text) {
        Pattern pattern = Pattern.compile("\\{\\{(.*?)}}");
        Matcher matcher = pattern.matcher(text);
        StringBuffer sb = new StringBuffer();

        while (matcher.find()) {
            String expr = matcher.group(1);
            String replacement = "";
            try {
                // Note: Java doesn't have a direct eval equivalent for arbitrary expressions
                // This is a simplified version that handles basic arithmetic
                replacement = String.valueOf(evalSimpleExpression(expr));
            } catch (Exception e) {
                replacement = "";
            }
            matcher.appendReplacement(sb, Matcher.quoteReplacement(replacement));
        }
        matcher.appendTail(sb);
        return sb.toString();
    }

    private static double evalSimpleExpression(String expr) {
        // Simple arithmetic expression evaluator
        // This handles basic +, -, *, / operations
        expr = expr.trim();

        // Handle parentheses recursively
        while (expr.contains("(")) {
            int openIdx = expr.lastIndexOf("(");
            int closeIdx = expr.indexOf(")", openIdx);
            if (closeIdx == -1) {
                throw new IllegalArgumentException("Mismatched parentheses");
            }
            String subExpr = expr.substring(openIdx + 1, closeIdx);
            double subResult = evalSimpleExpression(subExpr);
            expr = expr.substring(0, openIdx) + subResult + expr.substring(closeIdx + 1);
        }

        // Handle addition and subtraction
        List<String> terms = new ArrayList<>();
        StringBuilder current = new StringBuilder();
        for (int i = 0; i < expr.length(); i++) {
            char c = expr.charAt(i);
            if ((c == '+' || c == '-') && i > 0 && !isOperator(expr.charAt(i-1))) {
                terms.add(current.toString().trim());
                current = new StringBuilder();
                current.append(c);
            } else {
                current.append(c);
            }
        }
        if (current.length() > 0) {
            terms.add(current.toString().trim());
        }

        if (terms.isEmpty()) {
            return 0;
        }

        double result = evaluateTerm(terms.get(0));
        for (int i = 1; i < terms.size(); i++) {
            String term = terms.get(i);
            if (term.startsWith("+")) {
                result += evaluateTerm(term.substring(1));
            } else if (term.startsWith("-")) {
                result -= evaluateTerm(term.substring(1));
            }
        }

        return result;
    }

    private static double evaluateTerm(String term) {
        term = term.trim();

        // Handle multiplication and division
        List<String> factors = new ArrayList<>();
        StringBuilder current = new StringBuilder();
        for (int i = 0; i < term.length(); i++) {
            char c = term.charAt(i);
            if ((c == '*' || c == '/') && i > 0) {
                factors.add(current.toString().trim());
                current = new StringBuilder();
                current.append(c);
            } else {
                current.append(c);
            }
        }
        if (current.length() > 0) {
            factors.add(current.toString().trim());
        }

        if (factors.isEmpty()) {
            return 0;
        }

        double result = Double.parseDouble(factors.get(0));
        for (int i = 1; i < factors.size(); i++) {
            String factor = factors.get(i);
            if (factor.startsWith("*")) {
                result *= Double.parseDouble(factor.substring(1));
            } else if (factor.startsWith("/")) {
                double divisor = Double.parseDouble(factor.substring(1));
                if (divisor == 0) {
                    throw new ArithmeticException("Division by zero");
                }
                result /= divisor;
            }
        }

        return result;
    }

    private static boolean isOperator(char c) {
        return c == '+' || c == '-' || c == '*' || c == '/';
    }
}

