public class Solution {
    public static String render_email_template(String template, Map<?, ?> data) {
        if (template == null) {
            throw new IllegalArgumentException("template must not be null");
        }
        if (data == null) {
            throw new IllegalArgumentException("data must not be null");
        }

        String renderedTemplate = template;
        for (Map.Entry<?, ?> entry : data.entrySet()) {
            Object keyObj = entry.getKey();
            if (!(keyObj instanceof String)) {
                throw new IllegalArgumentException("keys must be strings");
            }
            String key = (String) keyObj;
            Object value = entry.getValue();
            String placeholder = "{{" + key + "}}";
            String stringValue = (value == null) ? "None" : value.toString();
            String sanitizedValue = escapeHtml(stringValue);
            renderedTemplate = renderedTemplate.replace(placeholder, sanitizedValue);
        }
        return renderedTemplate;
    }

    private static String escapeHtml(String input) {
        if (input == null) {
            return null;
        }
        StringBuilder escaped = new StringBuilder(input.length() * 2);
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            switch (c) {
                case '&':
                    escaped.append("&amp;");
                    break;
                case '<':
                    escaped.append("&lt;");
                    break;
                case '>':
                    escaped.append("&gt;");
                    break;
                case '"':
                    escaped.append("&quot;");
                    break;
                case '\'':
                    escaped.append("&#x27;");
                    break;
                default:
                    escaped.append(c);
            }
        }
        return escaped.toString();
    }
}

