import java.util.concurrent.TimeUnit;

public class Solution {
    public static String execute_script(String scriptContent) {
        if (scriptContent == null) {
            throw new IllegalArgumentException("script_content must be a non-null string");
        }
        // Block dangerous constructs
        List<String> forbidden = Arrays.asList(
            "__import__", "import", "open(", "exec(", "eval(",
            "os.", "subprocess.", "importlib", "globals", "locals", "compile"
        );
        for (String tok : forbidden) {
            if (scriptContent.contains(tok)) {
                throw new IllegalArgumentException("Forbidden construct detected: " + tok);
            }
        }
        // Also block built-in access
        if (scriptContent.contains("__builtins__")) {
            throw new IllegalArgumentException("Forbidden construct detected");
        }

        try {
            ProcessBuilder pb = new ProcessBuilder("python3", "-c", scriptContent);
            pb.redirectErrorStream(true);
            Process process = pb.start();

            // Set a timeout to prevent runaway scripts
            boolean finished = process.waitFor(5, TimeUnit.SECONDS);
            if (!finished) {
                process.destroyForcibly();
                throw new RuntimeException("Script execution timed out");
            }

            int exitCode = process.exitValue();
            // Capture output
            ByteArrayOutputStream buffer = new ByteArrayOutputStream();
            try (InputStream is = process.getInputStream()) {
                byte[] data = new byte[4096];
                int n;
                while ((n = is.read(data)) != -1) {
                    buffer.write(data, 0, n);
                }
            }
            String output = buffer.toString("UTF-8");
            if (exitCode != 0) {
                throw new RuntimeException("Script exited with error code " + exitCode + ": " + output);
            }
            return "Execution Result: " + output;
        } catch (IOException | InterruptedException e) {
            throw new RuntimeException("Failed to execute script", e);
        }
    }
}

