    }

    public static String save_firmware_blob(String blob_name, byte[] blob_bytes, String upload_dir) {
        if (blob_name == null || blob_name.trim().isEmpty()) {
            throw new IllegalArgumentException("blob_name cannot be null or empty");
        }
        if (blob_bytes == null) {
            throw new IllegalArgumentException("blob_bytes cannot be null");
        }
        if (upload_dir == null || upload_dir.trim().isEmpty()) {
            throw new IllegalArgumentException("upload_dir cannot be null or empty");
        }

        if (blob_bytes.length > 256 * 1024) {
            throw new IllegalArgumentException("blob_bytes exceeds maximum size of 256KB");
        }

        String name = blob_name.trim();
        String lower = name.toLowerCase();
        if (!lower.endsWith(".bin")) {
            throw new IllegalArgumentException("unsupported extension");
        }

        String base = Paths.get(name).getFileName().toString();
        if (base.isEmpty() || base.equals(".") || base.equals("..")) {
            throw new IllegalArgumentException("invalid blob_name");
        }
        // Reject double extensions: ensure the last extension is exactly ".bin" and no other dot after
        int lastDot = base.lastIndexOf('.');
        if (lastDot == -1 || !base.substring(lastDot).toLowerCase().equals(".bin")) {
            throw new IllegalArgumentException("invalid blob_name");
        }
        // Ensure only one .bin at the end
        String withoutExt = base.substring(0, lastDot);
        if (withoutExt.toLowerCase().endsWith(".bin")) {
            throw new IllegalArgumentException("double extension not allowed");
        }

