import java.nio.file.*;
import java.io.FileNotFoundException;
import java.io.IOException;

public class Solution {
    public static String image_upload(String source, String destination) throws IOException {
        if (source == null || destination == null) {
            throw new IllegalArgumentException("source and destination must not be null");
        }
        if (source.isBlank()) {
            throw new IllegalArgumentException("source must not be empty");
        }
        if (destination.isBlank()) {
            throw new IllegalArgumentException("destination must not be empty");
        }

        Path srcPath = Paths.get(source);
        if (!Files.exists(srcPath) || !Files.isRegularFile(srcPath)) {
            throw new FileNotFoundException("Source file not found: " + source);
        }

        String srcExt = getExtension(source).toLowerCase();
        String dstExt = getExtension(destination).toLowerCase();
        if (!isAllowedExtension(srcExt)) {
            throw new IllegalArgumentException("Unsupported source image extension");
        }
        if (!isAllowedExtension(dstExt)) {
            throw new IllegalArgumentException("Unsupported destination image extension");
        }

        Path dstPath = Paths.get(destination);
        Path parent = dstPath.getParent();
        if (parent != null) {
            Files.createDirectories(parent);
        }
        Files.copy(srcPath, dstPath, StandardCopyOption.REPLACE_EXISTING);
        return "Image uploaded successfully to " + destination;
    }

    private static String getExtension(String filename) {
        int dotIndex = filename.lastIndexOf('.');
        return dotIndex >= 0 ? filename.substring(dotIndex) : "";
    }

    private static boolean isAllowedExtension(String ext) {
        return ext.equals(".jpg") || ext.equals(".jpeg") || ext.equals(".png") || ext.equals(".gif");
    }
}

