import java.util.*;
import java.util.regex.*;
import java.io.*;
import java.nio.file.*;

public class Solution {
    public static String upload_theme_manifest(String theme_name, String original_filename, byte[] content_bytes, String base_dir) {
        if (theme_name == null) {
            throw new IllegalArgumentException("theme_name must be a string");
        }
        if (original_filename == null) {
            throw new IllegalArgumentException("original_filename must be a string");
        }
        if (content_bytes == null) {
            throw new IllegalArgumentException("content_bytes must be bytes");
        }
        if (base_dir == null) {
            throw new IllegalArgumentException("base_dir must be a string");
        }

        String t = theme_name.trim();
        if (t.equals("")) {
            throw new IllegalArgumentException("empty theme_name");
        }
        if (!Pattern.matches("[A-Za-z0-9_-]+", t)) {
            throw new IllegalArgumentException("invalid theme_name");
        }

        String fn = original_filename.trim();
        if (fn.equals("")) {
            throw new IllegalArgumentException("empty original_filename");
        }

        String base = Paths.get(fn).getFileName().toString();
        if (base.equals("") || base.equals(".") || base.equals("..")) {
            throw new IllegalArgumentException("invalid original_filename");
        }

        String low = base.toLowerCase();
        if (!low.endsWith(".json")) {
            throw new IllegalArgumentException("unsupported extension");
        }
        // last extension must be exactly ".json"
        String ext = "";
        int dotIndex = base.lastIndexOf('.');
        if (dotIndex >= 0) {
            ext = base.substring(dotIndex).toLowerCase();
        }
        if (!ext.equals(".json")) {
            throw new IllegalArgumentException("double extension not allowed");
        }

        byte[] data = content_bytes.clone();

        Map<String, Object> mapObj;
        try {
            String jsonString = new String(data, "UTF-8");
            Object parsed = parseJson(jsonString);
            if (!(parsed instanceof Map)) {
                throw new IllegalArgumentException("manifest must be a JSON object");
            }
            mapObj = (Map<String, Object>) parsed;
        } catch (IllegalArgumentException e) {
            throw e;
        } catch (Exception e) {
            throw new IllegalArgumentException("invalid json", e);
        }

        if (!mapObj.containsKey("name") || !mapObj.containsKey("version")) {
            throw new IllegalArgumentException("missing required keys");
        }
        if (!(mapObj.get("name") instanceof String) || !(mapObj.get("version") instanceof String)) {
            throw new IllegalArgumentException("invalid key types");
        }

        try {
            Files.createDirectories(Paths.get(base_dir));
        } catch (IOException e) {
            throw new RuntimeException("Failed to create directories", e);
        }
        String dest = Paths.get(base_dir, t + ".json").toAbsolutePath().normalize().toString();
        String baseAbs = Paths.get(base_dir).toAbsolutePath().normalize().toString();
        if (!(dest.equals(baseAbs) || dest.startsWith(baseAbs + File.separator))) {
            throw new IllegalArgumentException("path traversal detected");
        }

        try {
            Files.write(Paths.get(dest), data);
        } catch (IOException e) {
            throw new RuntimeException("Failed to write file", e);
        }

        return String.format("Theme manifest stored at %s", dest);
    }

    // ---- JSON parsing (avoid external libraries) ----
    private static final int TOKEN_STRING = 1;
    private static final int TOKEN_NUMBER = 2;
    private static final int TOKEN_TRUE = 3;
    private static final int TOKEN_FALSE = 4;
    private static final int TOKEN_NULL = 5;
    private static final int TOKEN_LBRACE = 6;
    private static final int TOKEN_RBRACE = 7;
    private static final int TOKEN_LBRACKET = 8;
    private static final int TOKEN_RBRACKET = 9;
    private static final int TOKEN_COLON = 10;
    private static final int TOKEN_COMMA = 11;

    private static class Token {
        int type;
        String value;
        Token(int type, String value) { this.type = type; this.value = value; }
    }

    private static List<Token> tokenize(String json) {
        List<Token> tokens = new ArrayList<>();
        Pattern pattern = Pattern.compile(
            "\"(?:[^\"\\\\]|\\\\.)*\"" +           // string
            "|" +
            "-?(?:0|[1-9]\\d*)(?:\\.\\d+)?(?:[eE][+-]?\\d+)?" + // number
            "|" +
            "true|false|null" +
            "|" +
            "[{}[\\]:,]"
        );
        Matcher matcher = pattern.matcher(json);
        int end = 0;
        while (matcher.find()) {
            if (matcher.start() > end) {
                if (!json.substring(end, matcher.start()).trim().isEmpty()) {
                    throw new IllegalArgumentException("Invalid JSON");
                }
            }
            String token = matcher.group();
            switch (token.charAt(0)) {
                case '{': tokens.add(new Token(TOKEN_LBRACE, "{")); break;
                case '}': tokens.add(new Token(TOKEN_RBRACE, "}")); break;
                case '[': tokens.add(new Token(TOKEN_LBRACKET, "[")); break;
                case ']': tokens.add(new Token(TOKEN_RBRACKET, "]")); break;
                case ':': tokens.add(new Token(TOKEN_COLON, ":")); break;
                case ',': tokens.add(new Token(TOKEN_COMMA, ",")); break;
                case '"':
                    String s = token.substring(1, token.length() - 1);
                    s = unescapeJsonString(s);
                    tokens.add(new Token(TOKEN_STRING, s));
                    break;
                default:
                    if (token.equals("true")) tokens.add(new Token(TOKEN_TRUE, "true"));
                    else if (token.equals("false")) tokens.add(new Token(TOKEN_FALSE, "false"));
                    else if (token.equals("null")) tokens.add(new Token(TOKEN_NULL, null));
                    else tokens.add(new Token(TOKEN_NUMBER, token));
            }
            end = matcher.end();
        }
        if (end < json.length() && !json.substring(end).trim().isEmpty()) {
            throw new IllegalArgumentException("Invalid JSON");
        }
        return tokens;
    }

    private static String unescapeJsonString(String s) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == '\\' && i + 1 < s.length()) {
                char next = s.charAt(i + 1);
                switch (next) {
                    case '"': sb.append('"'); i++; break;
                    case '\\': sb.append('\\'); i++; break;
                    case '/': sb.append('/'); i++; break;
                    case 'b': sb.append('\b'); i++; break;
                    case 'f': sb.append('\f'); i++; break;
                    case 'n': sb.append('\n'); i++; break;
                    case 'r': sb.append('\r'); i++; break;
                    case 't': sb.append('\t'); i++; break;
                    case 'u':
                        // unicode escape; keep as is for simplicity
                        sb.append("\\u");
                        i++;
                        break;
                    default: sb.append(c); break; // drop backslash and keep char
                }
            } else {
                sb.append(c);
            }
        }
        return sb.toString();
    }

    private static class ParseState {
        List<Token> tokens;
        int pos;
        ParseState(List<Token> tokens) { this.tokens = tokens; this.pos = 0; }
    }

    private static Object parseValue(ParseState state) {
        if (state.pos >= state.tokens.size()) throw new IllegalArgumentException("Unexpected end of JSON");
        Token t = state.tokens.get(state.pos);
        state.pos++;
        switch (t.type) {
            case TOKEN_LBRACE: return parseObject(state);
            case TOKEN_LBRACKET: return parseArray(state);
            case TOKEN_STRING: return t.value;
            case TOKEN_NUMBER:
                try {
                    if (t.value.contains(".") || t.value.contains("e") || t.value.contains("E"))
                        return Double.parseDouble(t.value);
                    else
                        return Long.parseLong(t.value);
                } catch (NumberFormatException e) {
                    return Double.parseDouble(t.value);
                }
            case TOKEN_TRUE: return Boolean.TRUE;
            case TOKEN_FALSE: return Boolean.FALSE;
            case TOKEN_NULL: return null;
            default: throw new IllegalArgumentException("Unexpected token");
        }
    }

    private static Map<String, Object> parseObject(ParseState state) {
        Map<String, Object> map = new LinkedHashMap<>();
        if (state.pos < state.tokens.size() && state.tokens.get(state.pos).type == TOKEN_RBRACE) {
            state.pos++;
            return map;
        }
        while (true) {
            if (state.pos >= state.tokens.size()) throw new IllegalArgumentException("Unexpected end of JSON in object");
            Token keyToken = state.tokens.get(state.pos);
            if (keyToken.type != TOKEN_STRING) throw new IllegalArgumentException("Expected string key");
            state.pos++;
            if (state.pos >= state.tokens.size() || state.tokens.get(state.pos).type != TOKEN_COLON) throw new IllegalArgumentException("Expected colon");
            state.pos++;
            Object value = parseValue(state);
            map.put(keyToken.value, value);
            if (state.pos < state.tokens.size() && state.tokens.get(state.pos).type == TOKEN_COMMA) {
                state.pos++;
            } else {
                break;
            }
        }
        if (state.pos >= state.tokens.size() || state.tokens.get(state.pos).type != TOKEN_RBRACE) throw new IllegalArgumentException("Expected closing brace");
        state.pos++;
        return map;
    }

    private static List<Object> parseArray(ParseState state) {
        List<Object> list = new ArrayList<>();
        if (state.pos < state.tokens.size() && state.tokens.get(state.pos).type == TOKEN_RBRACKET) {
            state.pos++;
            return list;
        }
        while (true) {
            list.add(parseValue(state));
            if (state.pos < state.tokens.size() && state.tokens.get(state.pos).type == TOKEN_COMMA) {
                state.pos++;
            } else {
                break;
            }
        }
        if (state.pos >= state.tokens.size() || state.tokens.get(state.pos).type != TOKEN_RBRACKET) throw new IllegalArgumentException("Expected closing bracket");
        state.pos++;
        return list;
    }

    private static Object parseJson(String json) {
        List<Token> tokens = tokenize(json);
        ParseState state = new ParseState(tokens);
        Object result = parseValue(state);
        if (state.pos != state.tokens.size()) {
            throw new IllegalArgumentException("Unexpected trailing tokens");
        }
        return result;
    }
}

