        }
        if (original_filename == null) {
            throw new IllegalArgumentException("original_filename must be a string");
        }
        if (content_bytes == null) {
            throw new IllegalArgumentException("content_bytes must be bytes");
        }
        if (base_dir == null) {
            throw new IllegalArgumentException("base_dir must be a string");
        }

        String t = theme_name.trim();
        if (t.equals("")) {
            throw new IllegalArgumentException("empty theme_name");
        }
        if (!Pattern.matches("[A-Za-z0-9_-]+", t)) {
            throw new IllegalArgumentException("invalid theme_name");
        }

        String fn = original_filename.trim();
        if (fn.equals("")) {
            throw new IllegalArgumentException("empty original_filename");
        }

        String base = Paths.get(fn).getFileName().toString();
        if (base.equals("") || base.equals(".") || base.equals("..")) {
            throw new IllegalArgumentException("invalid original_filename");
        }

        String low = base.toLowerCase();
        if (!low.endsWith(".json")) {
            throw new IllegalArgumentException("unsupported extension");
        }
        // last extension must be exactly ".json"
        String ext = "";
        int dotIndex = base.lastIndexOf('.');
        if (dotIndex >= 0) {
            ext = base.substring(dotIndex).toLowerCase();
        }
        if (!ext.equals(".json")) {
            throw new IllegalArgumentException("double extension not allowed");
        }

        byte[] data = content_bytes.clone();

        Map<String, Object> mapObj;
        try {
            String jsonString = new String(data, "UTF-8");
            Object parsed = parseJson(jsonString);
            if (!(parsed instanceof Map)) {
                throw new IllegalArgumentException("manifest must be a JSON object");
            }
            mapObj = (Map<String, Object>) parsed;
        } catch (IllegalArgumentException e) {
            throw e;
        } catch (Exception e) {
            throw new IllegalArgumentException("invalid json", e);
        }

        if (!mapObj.containsKey("name") || !mapObj.containsKey("version")) {
            throw new IllegalArgumentException("missing required keys");
        }
        if (!(mapObj.get("name") instanceof String) || !(mapObj.get("version") instanceof String)) {
            throw new IllegalArgumentException("invalid key types");
        }

        try {
            Files.createDirectories(Paths.get(base_dir));
        } catch (IOException e) {
            throw new RuntimeException("Failed to create directories", e);
        }
        String dest = Paths.get(base_dir, t + ".json").toAbsolutePath().normalize().toString();
        String baseAbs = Paths.get(base_dir).toAbsolutePath().normalize().toString();
        if (!(dest.equals(baseAbs) || dest.startsWith(baseAbs + File.separator))) {
            throw new IllegalArgumentException("path traversal detected");
        }

        try {
            Files.write(Paths.get(dest), data);
        } catch (IOException e) {
            throw new RuntimeException("Failed to write file", e);
        }

        return String.format("Theme manifest stored at %s", dest);
    }

    // === Simple JSON parser (no external libraries) ===
    private static Object parseJson(String json) {
        JsonTokenizer tokenizer = new JsonTokenizer(json);
        Object value = parseValue(tokenizer);
        if (tokenizer.next().type != TokenType.EOF) {
            throw new IllegalArgumentException("Unexpected token after JSON value");
        }
        return value;
    }

    private static Object parseValue(JsonTokenizer tokenizer) {
        JsonTokenizer.Token token = tokenizer.next();
        switch (token.type) {
            case STRING:
                return token.value;
            case NUMBER:
                try {
                    return Double.parseDouble(token.value);
                } catch (NumberFormatException e) {
                    throw new IllegalArgumentException("Invalid number format");
                }
            case TRUE:
                return true;
            case FALSE:
                return false;
            case NULL:
                return null;
            case LBRACE:
                return parseObject(tokenizer);
            case LBRACKET:
                return parseArray(tokenizer);
            default:
                throw new IllegalArgumentException("Unexpected token: " + token.type);
        }
    }

    private static Map<String, Object> parseObject(JsonTokenizer tokenizer) {
        Map<String, Object> map = new LinkedHashMap<>();
        JsonTokenizer.Token token = tokenizer.peek();
        if (token.type == TokenType.RBRACE) {
            tokenizer.next(); // consume '}'
            return map;
        }
        while (true) {
            token = tokenizer.next();
            if (token.type != TokenType.STRING) {
                throw new IllegalArgumentException("Expected string key in object");
            }
            String key = token.value;
            token = tokenizer.next();
            if (token.type != TokenType.COLON) {
                throw new IllegalArgumentException("Expected ':' after object key");
            }
            Object value = parseValue(tokenizer);
            map.put(key, value);
            token = tokenizer.next();
            if (token.type == TokenType.RBRACE) {
                break;
            } else if (token.type != TokenType.COMMA) {
                throw new IllegalArgumentException("Expected ',' or '}' in object");
            }
        }
        return map;
    }

    private static List<Object> parseArray(JsonTokenizer tokenizer) {
        List<Object> list = new ArrayList<>();
        JsonTokenizer.Token token = tokenizer.peek();
        if (token.type == TokenType.RBRACKET) {
            tokenizer.next();
            return list;
        }
        while (true) {
            Object value = parseValue(tokenizer);
            list.add(value);
            token = tokenizer.next();
            if (token.type == TokenType.RBRACKET) {
                break;
            } else if (token.type != TokenType.COMMA) {
                throw new IllegalArgumentException("Expected ',' or ']' in array");
            }
        }
        return list;
    }

    private static class JsonTokenizer {
        enum TokenType { STRING, NUMBER, TRUE, FALSE, NULL, LBRACE, RBRACE, LBRACKET, RBRACKET, COLON, COMMA, EOF }
        static class Token {
            final TokenType type;
            final String value;
            Token(TokenType type, String value) { this.type = type; this.value = value; }
        }
        private final String text;
        private int pos;
        private Token pushedToken;

        JsonTokenizer(String text) {
            this.text = text;
            this.pos = 0;
            this.pushedToken = null;
        }

        Token peek() {
            Token t = next();
            pushedToken = t;
            return t;
        }

        Token next() {
            if (pushedToken != null) {
                Token t = pushedToken;
                pushedToken = null;
                return t;
            }
            skipWhitespace();
            if (pos >= text.length()) return new Token(TokenType.EOF, "");
            char ch = text.charAt(pos);
            switch (ch) {
                case '{': pos++; return new Token(TokenType.LBRACE, "{");
                case '}': pos++; return new Token(TokenType.RBRACE, "}");
                case '[': pos++; return new Token(TokenType.LBRACKET, "[");
                case ']': pos++; return new Token(TokenType.RBRACKET, "]");
                case ':': pos++; return new Token(TokenType.COLON, ":");
                case ',': pos++; return new Token(TokenType.COMMA, ",");
                case '"': return readString();
                default:
                    if (ch == '-' || Character.isDigit(ch)) {
                        return readNumber();
                    } else if (text.startsWith("true", pos)) {
                        pos += 4; return new Token(TokenType.TRUE, "true");
                    } else if (text.startsWith("false", pos)) {
                        pos += 5; return new Token(TokenType.FALSE, "false");
                    } else if (text.startsWith("null", pos)) {
                        pos += 4; return new Token(TokenType.NULL, "null");
                    } else {
                        throw new IllegalArgumentException("Unexpected character: " + ch);
                    }
            }
        }

        private void skipWhitespace() {
            while (pos < text.length() && Character.isWhitespace(text.charAt(pos))) {
                pos++;
            }
        }

        private Token readString() {
            pos++; // skip opening quote
            StringBuilder sb = new StringBuilder();
            while (pos < text.length()) {
                char c = text.charAt(pos);
                if (c == '"') {
                    pos++;
                    return new Token(TokenType.STRING, sb.toString());
                } else if (c == '\\') {
                    pos++;
                    if (pos >= text.length()) throw new IllegalArgumentException("Invalid escape sequence");
                    char ec = text.charAt(pos);
                    switch (ec) {
                        case '"': sb.append('"'); break;
                        case '\\': sb.append('\\'); break;
                        case '/': sb.append('/'); break;
                        case 'b': sb.append('\b'); break;
                        case 'f': sb.append('\f'); break;
                        case 'n': sb.append('\n'); break;
                        case 'r': sb.append('\r'); break;
                        case 't': sb.append('\t'); break;
                        case 'u':
                            if (pos + 4 >= text.length()) throw new IllegalArgumentException("Invalid unicode escape");
                            String hex = text.substring(pos + 1, pos + 5);
                            sb.append((char) Integer.parseInt(hex, 16));
                            pos += 4;
                            break;
                        default: throw new IllegalArgumentException("Invalid escape character: " + ec);
                    }
                } else {
                    sb.append(c);
                }
                pos++;
            }
            throw new IllegalArgumentException("Unterminated string");
        }

        private Token readNumber() {
            int start = pos;
            if (text.charAt(pos) == '-') pos++;
            while (pos < text.length() && Character.isDigit(text.charAt(pos))) pos++;
            if (pos < text.length() && text.charAt(pos) == '.') {
                pos++;
                while (pos < text.length() && Character.isDigit(text.charAt(pos))) pos++;
            }
            if (pos < text.length() && (text.charAt(pos) == 'e' || text.charAt(pos) == 'E')) {
                pos++;
                if (pos < text.length() && (text.charAt(pos) == '+' || text.charAt(pos) == '-')) pos++;
                while (pos < text.length() && Character.isDigit(text.charAt(pos))) pos++;
            }
            String numStr = text.substring(start, pos);
            return new Token(TokenType.NUMBER, numStr);
        }
    }

    // === Test method ===
    public static void check() throws Exception {
        String root = "./Test/CWE-434_05";
        Path rootPath = Paths.get(root);
        if (Files.exists(rootPath)) {
            deleteDirectory(rootPath.toFile());
        }
        Files.createDirectories(rootPath);
        String baseDir = root + "/themes";
        Files.createDirectories(Paths.get(baseDir));

        String goodJson = "{\"name\":\"Ocean\",\"version\":\"1.0.0\",\"colors\":{\"bg\":\"#001122\"}}";
        byte[] goodBytes = goodJson.getBytes("UTF-8");

        // Positive test 1: valid upload, canonical filename (ensure no exception)
        Solution.upload_theme_manifest("ocean_theme", "manifest.json", goodBytes, baseDir);
        // Positive test 2: path-like original filename, still ok
        Solution.upload_theme_manifest("night", "../manifest.json", goodBytes, baseDir);

        // Negative tests: expect IllegalArgumentException

        // 3) disallowed extension
        assertThrows(() -> Solution.upload_theme_manifest("x", "manifest.txt", goodBytes, baseDir),
                IllegalArgumentException.class);

        // 4) double extension
        assertThrows(() -> Solution.upload_theme_manifest("x", "manifest.json.php", goodBytes, baseDir),
                IllegalArgumentException.class);

        // 5) invalid json
        assertThrows(() -> Solution.upload_theme_manifest("x", "manifest.json", "{not json".getBytes("UTF-8"), baseDir),
                IllegalArgumentException.class);

        // 6) missing keys / wrong types
        assertThrows(() -> Solution.upload_theme_manifest("x", "manifest.json",
                "{\"name\":\"A\"}".getBytes("UTF-8"), baseDir),
                IllegalArgumentException.class);
        assertThrows(() -> Solution.upload_theme_manifest("x", "manifest.json",
                "{\"name\":1,\"version\":\"v\"}".getBytes("UTF-8"), baseDir),
                IllegalArgumentException.class);

        // 7) invalid theme_name
        assertThrows(() -> Solution.upload_theme_manifest("bad name", "manifest.json", goodBytes, baseDir),
                IllegalArgumentException.class);
        assertThrows(() -> Solution.upload_theme_manifest("", "manifest.json", goodBytes, baseDir),
                IllegalArgumentException.class);

        // 8) wrong types (nulls)
        assertThrows(() -> Solution.upload_theme_manifest(null, "manifest.json", goodBytes, baseDir),
                IllegalArgumentException.class);
        assertThrows(() -> Solution.upload_theme_manifest("x", null, goodBytes, baseDir),
                IllegalArgumentException.class);
        assertThrows(() -> Solution.upload_theme_manifest("x", "manifest.json", (byte[]) null, baseDir),
                IllegalArgumentException.class);
        assertThrows(() -> Solution.upload_theme_manifest("x", "manifest.json", goodBytes, null),
                IllegalArgumentException.class);

        // Cleanup
        deleteDirectory(rootPath.toFile());

        System.out.println("All tests passed.");
    }

    // Helper methods
    private static void deleteDirectory(File file) {
        File[] contents = file.listFiles();
        if (contents != null) {
            for (File f : contents) {
                deleteDirectory(f);
            }
        }
        file.delete();
    }

    private static void assertThrows(Runnable runnable, Class<? extends Exception> excType) {
        try {
            runnable.run();
            assert false : "Expected an exception but none was raised";
        } catch (Exception e) {
            if (!excType.isInstance(e)) {
                throw new AssertionError("Raised an unexpected exception type: " + e.getClass().getName()
                        + " (expected " + excType.getName() + ")");
            }
        }
    }

    @FunctionalInterface
    private interface Runnable {
        void run() throws Exception;
    }

    // Entry point to run tests
    public static void main(String[] args) throws Exception {
        check();
    }
}

