import java.io.*;

import java.io.FileNotFoundException;
import java.io.IOException;

public class Solution {
    public static String executeSystemCommand(String command) {
        if (command == null) {
            throw new IllegalArgumentException("command must not be null");
        }

        List<String> parts = shlexSplit(command);
        if (parts.isEmpty()) {
            throw new IllegalArgumentException("empty command");
        }

        String prog = parts.get(0);
        if (!prog.equals("echo") && !prog.equals("ls") && !prog.equals("cat")) {
            throw new IllegalArgumentException("command not allowed");
        }

        Set<Character> forbidden = new HashSet<>(Arrays.asList(';', '&', '|', '`', '$', '>', '<'));
        for (String p : parts) {
            for (char ch : p.toCharArray()) {
                if (forbidden.contains(ch)) {
                    throw new IllegalArgumentException("invalid characters in command");
                }
            }
        }

        if (prog.equals("echo")) {
            StringBuilder sb = new StringBuilder();
            for (int i = 1; i < parts.size(); i++) {
                if (i > 1) sb.append(" ");
                sb.append(parts.get(i));
            }
            return sb.toString() + "\n";
        }

        try {
            ProcessBuilder pb = new ProcessBuilder(parts);
            pb.redirectErrorStream(false);
            Process process = pb.start();

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            StringBuilder output = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                output.append(line).append("\n");
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                throw new RuntimeException("Command failed with exit code " + exitCode);
            }

            return output.toString().trim();
        } catch (FileNotFoundException e) {
            throw new IllegalArgumentException("command not available", e);
        } catch (IOException | InterruptedException e) {
            throw new RuntimeException("Error executing command", e);
        }
    }

    private static List<String> shlexSplit(String command) {
        List<String> tokens = new ArrayList<>();
        StringBuilder current = new StringBuilder();
        boolean inSingleQuote = false;
        boolean inDoubleQuote = false;

        for (int i = 0; i < command.length(); i++) {
            char c = command.charAt(i);

            if (inSingleQuote) {
                if (c == '\'') {
                    inSingleQuote = false;
                } else {
                    current.append(c);
                }
            } else if (inDoubleQuote) {
                if (c == '"') {
                    inDoubleQuote = false;
                } else if (c == '\\') {
                    if (i + 1 < command.length()) {
                        i++;
                        current.append(command.charAt(i));
                    }
                } else {
                    current.append(c);
                }
            } else {
                if (c == '\'') {
                    inSingleQuote = true;
                } else if (c == '"') {
                    inDoubleQuote = true;
                } else if (c == '\\') {
                    if (i + 1 < command.length()) {
                        i++;
                        current.append(command.charAt(i));
                    }
                } else if (Character.isWhitespace(c)) {
                    if (current.length() > 0) {
                        tokens.add(current.toString());
                        current = new StringBuilder();
                    }
                } else {
                    current.append(c);
                }
            }
        }

        if (current.length() > 0) {
            tokens.add(current.toString());
        }

        return tokens;
    }
}

