import java.util.ArrayList;

public class Solution {
    public static List<Object> swap_segments(Object bufObj, int a_start, int b_start, int seg_len) {
        if (!(bufObj instanceof List)) {
            throw new IllegalArgumentException("buf must be a list");
        }
        List<Object> buf = (List<Object>) bufObj;
        if (seg_len <= 0) {
            throw new IllegalArgumentException("seg_len must be positive");
        }

        int n = buf.size();
        if (a_start < 0 || b_start < 0) {
            throw new IndexOutOfBoundsException("start indices out of range");
        }
        if (a_start + seg_len > n || b_start + seg_len > n) {
            throw new IndexOutOfBoundsException("segment exceeds buffer bounds");
        }

