        int a0 = a_start;
        int a1 = a_start + seg_len;
        int b0 = b_start;
        int b1 = b_start + seg_len;
        if (!(a1 <= b0 || b1 <= a0)) {
            throw new IllegalArgumentException("segments overlap");
        }

        // safe in-place swap
        for (int i = 0; i < seg_len; i++) {
            Object temp = buf.get(a_start + i);
            buf.set(a_start + i, buf.get(b_start + i));
            buf.set(b_start + i, temp);
        }
