public class Solution {
    public static String update_order_address(Integer user_id, String token, String order_id, String new_address, Map<String, Object> token_db, Map<String, Object> order_owner) {
        if (user_id != null && !(user_id instanceof Integer)) {
            throw new IllegalArgumentException("user_id must be int or None");
        }
        if (token != null && !(token instanceof String)) {
            throw new IllegalArgumentException("token must be str or None");
        }
        if (!(order_id instanceof String)) {
            throw new IllegalArgumentException("order_id must be str");
        }
        if (!(new_address instanceof String)) {
            throw new IllegalArgumentException("new_address must be str");
        }
        if (!(token_db instanceof Map) || !(order_owner instanceof Map)) {
            throw new IllegalArgumentException("token_db and order_owner must be dicts");
        }

        if (user_id == null) {
            return "Authentication required.";
        }
        if (order_id.trim().isEmpty()) {
            throw new IllegalArgumentException("order_id must be non-empty");
        }

        // Strong auth: token must exist, be known, and belong to this user.
        if (token == null || token.trim().isEmpty() || !token_db.containsKey(token)) {
            return "Invalid token.";
        }
        Object mappedUidObj = token_db.get(token);
        if (!(mappedUidObj instanceof Integer)) {
            throw new IllegalArgumentException("invalid token_db mapping");
        }
        int mappedUid = (Integer) mappedUidObj;
        if (mappedUid != user_id) {
            return "Invalid token.";
        }

        if (!order_owner.containsKey(order_id)) {
            return "Order not found.";
        }
        Object ownerObj = order_owner.get(order_id);
        if (!(ownerObj instanceof Integer)) {
            throw new IllegalArgumentException("invalid order_owner mapping");
        }
        int owner = (Integer) ownerObj;

        return (owner == user_id) ? "Address updated." : "Access denied.";
    }
}

