import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.time.format.DateTimeParseException;

public class Solution {
    public static String access_exam(String student_id, String exam_id, String current_time, Map<String, Object> schedule, Map<String, Object> submissions) {
        // Basic null checks for the maps (optional but safe)
        if (schedule == null) {
            throw new IllegalArgumentException("schedule must not be null");
        }
        if (submissions == null) {
            throw new IllegalArgumentException("submissions must not be null");
        }

        String sid = student_id;
        String eid = exam_id;
        String ctime = current_time;

        if (!schedule.containsKey(eid)) {
            return "Exam not found.";
        }

        Object schedValue = schedule.get(eid);
        if (!(schedValue instanceof List)) {
            throw new IllegalArgumentException("schedule values must be lists");
        }
        List<?> schedList = (List<?>) schedValue;
        if (schedList.size() != 2) {
            throw new IllegalArgumentException("schedule values must have exactly 2 elements");
        }
        Object startObj = schedList.get(0);
        Object endObj = schedList.get(1);
        if (!(startObj instanceof String) || !(endObj instanceof String)) {
            throw new IllegalArgumentException("schedule values must be timestamp strings");
        }
        String startStr = (String) startObj;
        String endStr = (String) endObj;

        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
        LocalDateTime now, start, end;
        try {
            now = LocalDateTime.parse(ctime, formatter);
            start = LocalDateTime.parse(startStr, formatter);
            end = LocalDateTime.parse(endStr, formatter);
        } catch (DateTimeParseException e) {
            throw new IllegalArgumentException("invalid time format");
        }

        if (now.isBefore(start) || now.isAfter(end)) {
            return "Exam unavailable.";
        }

        Object alreadyObj = submissions.getOrDefault(eid, new ArrayList<>());
        if (!(alreadyObj instanceof List)) {
            throw new IllegalArgumentException("submissions values must be lists");
        }
        List<?> already = (List<?>) alreadyObj;

        if (already.contains(sid)) {
            return "Exam already submitted.";
        } else {
            return "Exam access granted.";
        }
    }
}

