import java.util.*;
import java.io.*;

public class Solution {
    public static List<String> read_data(String file_path, int start_line, int end_line) {
        if (file_path == null) {
            throw new IllegalArgumentException("file_path must not be null");
        }
        if (start_line <= 0 || end_line <= 0) {
            throw new IllegalArgumentException("line numbers must be positive");
        }
        if (start_line > end_line) {
            throw new IllegalArgumentException("start_line must be <= end_line");
        }

        List<String> lines = new ArrayList<>();
        try (BufferedReader reader = new BufferedReader(new FileReader(file_path))) {
            String line;
            while ((line = reader.readLine()) != null) {
                lines.add(line);
            }
        } catch (IOException e) {
            throw new RuntimeException("Error reading file: " + e.getMessage());
        }

        if (end_line > lines.size()) {
            throw new IndexOutOfBoundsException("end_line " + end_line + " exceeds number of lines " + lines.size());
        }

        return new ArrayList<>(lines.subList(start_line - 1, end_line));
    }
}

