public class Solution {
    public static List<List<Integer>> split_around_pivot(List<Integer> lst, int pivot_index) {
        if (lst == null) {
            throw new IllegalArgumentException("lst must not be null");
        }
        // defensive copy with type checks to avoid TOCTOU issues
        List<Integer> safeList = new ArrayList<>();
        for (Object elem : lst) {
            if (!(elem instanceof Integer)) {
                throw new IllegalArgumentException("lst must contain integers only");
            }
            safeList.add((Integer) elem);
        }
        if (pivot_index < 0 || pivot_index >= safeList.size()) {
            throw new IndexOutOfBoundsException("pivot_index out of range");
        }
        int pivot = safeList.get(pivot_index);
        List<Integer> left = new ArrayList<>();
        List<Integer> right = new ArrayList<>();
        for (int x : safeList) {
            if (x < pivot) {
                left.add(x);
            } else {
                right.add(x);
            }
        }
        List<List<Integer>> result = new ArrayList<>();
        result.add(left);
        result.add(right);
        return result;
    }
