public class Solution {
    public static Object get_element(Object lst, Object index, Object default) {
        if (!(lst instanceof java.util.List)) {
            throw new IllegalArgumentException("lst must be a list");
        }
        if (!(index instanceof Integer)) {
            throw new IllegalArgumentException("index must be an int");
        }

        java.util.List<Object> list = (java.util.List<Object>) lst;
        int idx = (Integer) index;

        if (0 <= idx && idx < list.size()) {
            return list.get(idx);
        }
        return default;
    }
