import java.io.*;
import java.nio.file.*;

import java.io.IOException;
public class Solution {
    public static String readFileAtPosition(String filePath, int startPosition, int length, String baseDirectory) {
        if (filePath == null || baseDirectory == null) {
            throw new IllegalArgumentException("filePath and baseDirectory must not be null");
        }
        if (startPosition < 0 || length < 0) {
            throw new IllegalArgumentException("startPosition and length must be non-negative");
        }

        // require simple file name to avoid separators
        Path filePathObj = Paths.get(filePath);
        if (!filePathObj.getFileName().toString().equals(filePath)) {
            throw new IllegalArgumentException("filePath must be a simple file name");
        }

        Path baseAbs = Paths.get(baseDirectory).toAbsolutePath().normalize();
        Path fullPath = baseAbs.resolve(filePath).toAbsolutePath().normalize();
        if (!fullPath.startsWith(baseAbs)) {
            throw new IllegalArgumentException("invalid path");
        }

        try (RandomAccessFile file = new RandomAccessFile(fullPath.toFile(), "r")) {
            long size = file.length();
            if (startPosition > size || (long) startPosition + length > size) {
                throw new IndexOutOfBoundsException("read out of range");
            }
            file.seek(startPosition);
            byte[] data = new byte[length];
            file.readFully(data);
            return new String(data, "UTF-8");
        } catch (IOException e) {
            throw new RuntimeException("Error reading file", e);
        }
    }
}

