import java.util.*;

public class Solution {
    public static String analyze_packet(List<Object> packets, int packet_index, int offset, int bytes_to_extract) {
        if (packet_index < 0 || offset < 0 || bytes_to_extract < 0) {
            throw new IllegalArgumentException("indices must be non-negative");
        }
        for (Object b : packets) {
            if (!(b instanceof Integer)) {
                throw new IllegalArgumentException("packets must be a list of integers");
            }
            int val = (Integer) b;
            if (val < 0 || val > 255) {
                throw new IllegalArgumentException("packet bytes must be in [0, 255]");
            }
        }

        int pos = 0;
        int current = 0;
        while (true) {
            if (pos + 2 > packets.size()) {
                throw new IndexOutOfBoundsException("packet_index out of range");
            }
            int ptype = (Integer) packets.get(pos);
            int size = (Integer) packets.get(pos + 1);
            // size is guaranteed to be 0..255 due to prior validation
            int payload_start = pos + 2;
            int payload_end = payload_start + size;
            if (payload_end > packets.size()) {
                throw new IndexOutOfBoundsException("truncated packet");
            }
            if (current == packet_index) {
                if (offset > size || offset + bytes_to_extract > size) {
                    throw new IndexOutOfBoundsException("extraction out of range");
                }
                int start = payload_start + offset;
                List<Object> data = packets.subList(start, start + bytes_to_extract);
                StringBuilder sb = new StringBuilder("Extracted Data: [");
                for (int i = 0; i < data.size(); i++) {
                    if (i > 0) sb.append(", ");
                    sb.append(data.get(i));
                }
                sb.append("]");
                return sb.toString();
            }
            pos = payload_end;
            current += 1;
        }
    }
}

