        return String.format("<html><head><title>%s</title></head><body>%s</body></html>", safeTitle, safeContent);
    }

    private static String htmlEscape(String input, boolean quote) {
        StringBuilder result = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            switch (c) {
                case '&':
                    result.append("&amp;");
                    break;
                case '<':
                    result.append("&lt;");
                    break;
                case '>':
                    result.append("&gt;");
                    break;
                case '"':
                    if (quote) {
                        result.append("&quot;");
                    } else {
                        result.append(c);
                    }
                    break;
                case '\'':
                    if (quote) {
                        result.append("&#x27;");
                    } else {
                        result.append(c);
                    }
                    break;
                default:
                    result.append(c);
                    break;
            }
        }
        return result.toString();
    }
}

