public class Solution {
    public static Map<String, Object> create_question(String question, Object options, String correct_option) {
        if (!(question instanceof String)) {
            throw new IllegalArgumentException("question must be a string");
        }
        if (!(options instanceof List)) {
            throw new IllegalArgumentException("options must be a non-empty list");
        }
        List<?> optList = (List<?>) options;
        if (optList.isEmpty()) {
            throw new IllegalArgumentException("options must be a non-empty list");
        }
        for (Object opt : optList) {
            if (!(opt instanceof String)) {
                throw new IllegalArgumentException("each option must be a string");
            }
        }
        if (!(correct_option instanceof String)) {
            throw new IllegalArgumentException("correct_option must be a string");
        }
        if (!optList.contains(correct_option)) {
            throw new IllegalArgumentException("correct_option must be in options");
        }

        String encoded_question = htmlEscape(question);
        List<Object> encoded_options = optList.stream()
                .map(opt -> htmlEscape((String) opt))
                .collect(Collectors.toList());
        String encoded_correct = htmlEscape(correct_option);

        Map<String, Object> result = new HashMap<>();
        result.put("question", encoded_question);
        result.put("options", encoded_options);
        result.put("correct_option", encoded_correct);
        return result;
    }

    private static String htmlEscape(String input) {
        StringBuilder output = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            switch (c) {
                case '&':
                    output.append("&amp;");
                    break;
                case '<':
                    output.append("&lt;");
                    break;
                case '>':
                    output.append("&gt;");
                    break;
                case '"':
                    output.append("&quot;");
                    break;
                case '\'':
                    output.append("&#x27;");
                    break;
                default:
                    output.append(c);
                    break;
            }
        }
        return output.toString();
    }
}

