public class Solution {

    public static Map<String, Object> submit_comment(Integer post_id, String user_id, String comment_text) {
        if (post_id == null) {
            throw new IllegalArgumentException("post_id must be an int");
        }
        if (post_id < 0) {
            throw new IllegalArgumentException("post_id must be non-negative");
        }
        if (user_id == null || comment_text == null) {
            throw new IllegalArgumentException("user_id and comment_text must be strings");
        }
