        result.put("post_id", post_id);
        result.put("user_id", htmlEscape(user_id, true));
        result.put("comment_text", htmlEscape(comment_text, true));
        return result;
    }

    public static Map<String, Object> submit_comment(Object post_id, String user_id, String comment_text) {
        if (!(post_id instanceof Integer)) {
            throw new IllegalArgumentException("post_id must be an int");
        }
        return submit_comment((Integer) post_id, user_id, comment_text);
    }

    private static String htmlEscape(String input, boolean quote) {
        StringBuilder output = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            switch (c) {
                case '&':
                    output.append("&amp;");
                    break;
                case '<':
                    output.append("&lt;");
                    break;
                case '>':
                    output.append("&gt;");
                    break;
                case '"':
                    if (quote) {
                        output.append("&quot;");
                    } else {
                        output.append(c);
                    }
                    break;
                case '\'':
                    if (quote) {
                        output.append("&#x27;");
                    } else {
                        output.append(c);
                    }
                    break;
                default:
                    output.append(c);
                    break;
            }
        }
        return output.toString();
    }
}

