import java.util.*;

public class Solution {
    public static List<String> parse_csv_line(String line) {
        if (!(line instanceof String)) {
            throw new IllegalArgumentException("line must be a string");
        }
        if (line.contains("\n") || line.contains("\r")) {
            throw new IllegalArgumentException("line must not contain newlines");
        }

        List<String> fields = new ArrayList<>();
        StringBuilder buf = new StringBuilder();
        boolean inQuotes = false;
        int i = 0;
        int n = line.length();

        while (i < n) {
            char ch = line.charAt(i);
            if (inQuotes) {
                if (ch == '"') {
                    // Either end of quoted field or escaped quote
                    if (i + 1 < n && line.charAt(i + 1) == '"') {
                        buf.append('"');
                        i += 2;
                        continue;
                    }
                    inQuotes = false;
                    i += 1;
                    continue;
                } else {
                    buf.append(ch);
                    i += 1;
                    continue;
                }
            } else {
                if (ch == '"') {
                    inQuotes = true;
                    i += 1;
                    continue;
                }
                if (ch == ',') {
                    fields.add(buf.toString());
                    buf = new StringBuilder();
                    i += 1;
                    continue;
                }
                buf.append(ch);
                i += 1;
            }
        }

        if (inQuotes) {
            throw new IllegalArgumentException("unterminated quoted field");
        }

        fields.add(buf.toString());
        return fields;
    }
}

