public class Solution {
    public static String decodeRle(String data) {
        if (!(data instanceof String)) {
            throw new IllegalArgumentException("data must be a string");
        }
        if (data.equals("")) {
            return "";
        }

        StringBuilder out = new StringBuilder();
        int i = 0;
        int n = data.length();

        while (i < n) {
            if (!Character.isDigit(data.charAt(i))) {
                throw new IllegalArgumentException("expected a count");
            }

            // parse multi-digit positive integer
            int j = i;
            while (j < n && Character.isDigit(data.charAt(j))) {
                j++;
