            String countStr = data.substring(i, j);
            // no leading '+' or '-' by construction; ensure positive and not zero
            int count = Integer.parseInt(countStr);
            if (count <= 0) {
                throw new IllegalArgumentException("count must be positive");
            }

            if (j >= n) {
                throw new IllegalArgumentException("missing character after count");
            }

            char ch = data.charAt(j);
            for (int k = 0; k < count; k++) {
                out.append(ch);
            }
            i = j + 1;
        }

        return out.toString();
    }
}

