public class Solution {
    public static String writeApiToken(String tokenPath, String token) {
        if (tokenPath == null || tokenPath.trim().isEmpty()) {
            throw new IllegalArgumentException("invalid token_path");
        }
        if (token == null) {
            throw new IllegalArgumentException("token must be a string");
        }

