        if (payloadBytes.length == 0) {
            throw new IllegalArgumentException("empty payload");
        }

        String text = validUtf8String(payloadBytes);

        int[] pos = new int[]{0};
        Object root = parseValue(text, pos);
        if (!(root instanceof Map)) {
            throw new IllegalArgumentException("payload must be a JSON object");
        }
        @SuppressWarnings("unchecked")
        Map<String, Object> objMap = (Map<String, Object>) root;

        if (!objMap.containsKey("environment") || !objMap.containsKey("flags")) {
            throw new IllegalArgumentException("missing required fields");
        }

        Object env = objMap.get("environment");
        Object flags = objMap.get("flags");

        if (!(env instanceof String) || ((String) env).isEmpty()) {
            throw new IllegalArgumentException("invalid environment");
        }
        if (!(flags instanceof List)) {
            throw new IllegalArgumentException("flags must be a list");
        }

        Map<String, Object> out = new HashMap<>();
        @SuppressWarnings("unchecked")
        List<Object> flagsList = (List<Object>) flags;
        for (Object f : flagsList) {
            if (!(f instanceof Map)) {
                throw new IllegalArgumentException("each flag must be an object");
            }
            @SuppressWarnings("unchecked")
            Map<String, Object> fMap = (Map<String, Object>) f;
            if (!fMap.containsKey("name") || !fMap.containsKey("enabled")) {
                throw new IllegalArgumentException("flag missing required fields");
            }
            Object name = fMap.get("name");
            Object enabled = fMap.get("enabled");
            if (!(name instanceof String) || ((String) name).isEmpty()) {
                throw new IllegalArgumentException("invalid flag name");
            }
            if (!(enabled instanceof Boolean)) {
                throw new IllegalArgumentException("enabled must be a boolean");
            }
            out.put((String) name, enabled);
        }

        return out;
    }

    private static String validUtf8String(byte[] bytes) {
        try {
            CharsetDecoder decoder = StandardCharsets.UTF_8.newDecoder();
            decoder.onMalformedInput(CodingErrorAction.REPORT);
            decoder.onUnmappableCharacter(CodingErrorAction.REPORT);
            CharBuffer charBuffer = decoder.decode(ByteBuffer.wrap(bytes));
            return charBuffer.toString();
        } catch (CharacterCodingException e) {
            throw new IllegalArgumentException("invalid UTF-8", e);
        }
    }

    private static Object parseValue(String json, int[] pos) {
        skipWhitespace(json, pos);
        if (pos[0] >= json.length()) {
            throw new IllegalArgumentException("unexpected end of JSON");
        }
        char c = json.charAt(pos[0]);
        if (c == '{') {
            return parseObject(json, pos);
        } else if (c == '[') {
            return parseArray(json, pos);
        } else if (c == '"') {
            return parseString(json, pos);
        } else if (c == 't' || c == 'f') {
            return parseBoolean(json, pos);
        } else if (c == 'n') {
            parseNull(json, pos);
            return null;
        } else {
            throw new IllegalArgumentException("unexpected character: " + c);
        }
    }

    private static Map<String, Object> parseObject(String json, int[] pos) {
        Map<String, Object> map = new HashMap<>();
        pos[0]++; // skip '{'
        skipWhitespace(json, pos);
        if (pos[0] < json.length() && json.charAt(pos[0]) == '}') {
            pos[0]++;
            return map;
        }
        while (true) {
            skipWhitespace(json, pos);
            if (pos[0] >= json.length()) throw new IllegalArgumentException("unexpected end of object");
            if (json.charAt(pos[0]) == '}') {
                pos[0]++;
                break;
            }
            // key
            String key = parseString(json, pos);
            skipWhitespace(json, pos);
            if (pos[0] >= json.length() || json.charAt(pos[0]) != ':') {
                throw new IllegalArgumentException("expected ':' after key");
            }
            pos[0]++; // skip ':'
            Object value = parseValue(json, pos);
            map.put(key, value);
            skipWhitespace(json, pos);
            if (pos[0] >= json.length()) throw new IllegalArgumentException("unexpected end of object");
            char c = json.charAt(pos[0]);
            if (c == '}') {
                pos[0]++;
                break;
            } else if (c == ',') {
                pos[0]++;
            } else {
                throw new IllegalArgumentException("expected ',' or '}' in object");
            }
        }
        return map;
    }

    private static List<Object> parseArray(String json, int[] pos) {
        List<Object> list = new ArrayList<>();
        pos[0]++; // skip '['
        skipWhitespace(json, pos);
        if (pos[0] < json.length() && json.charAt(pos[0]) == ']') {
            pos[0]++;
            return list;
        }
        while (true) {
            Object value = parseValue(json, pos);
            list.add(value);
            skipWhitespace(json, pos);
            if (pos[0] >= json.length()) throw new IllegalArgumentException("unexpected end of array");
            char c = json.charAt(pos[0]);
            if (c == ']') {
                pos[0]++;
                break;
            } else if (c == ',') {
                pos[0]++;
            } else {
                throw new IllegalArgumentException("expected ',' or ']' in array");
            }
        }
        return list;
    }

    private static String parseString(String json, int[] pos) {
        if (pos[0] >= json.length() || json.charAt(pos[0]) != '"') {
            throw new IllegalArgumentException("expected string");
        }
        pos[0]++; // skip opening quote
        StringBuilder sb = new StringBuilder();
        while (pos[0] < json.length()) {
            char c = json.charAt(pos[0]);
            if (c == '"') {
                pos[0]++;
                return sb.toString();
            } else if (c == '\\') {
                pos[0]++;
                if (pos[0] >= json.length()) throw new IllegalArgumentException("unterminated escape");
                char next = json.charAt(pos[0]);
                switch (next) {
                    case '"': sb.append('"'); break;
                    case '\\': sb.append('\\'); break;
                    case '/': sb.append('/'); break;
                    case 'b': sb.append('\b'); break;
                    case 'f': sb.append('\f'); break;
                    case 'n': sb.append('\n'); break;
                    case 'r': sb.append('\r'); break;
                    case 't': sb.append('\t'); break;
                    case 'u':
                        if (pos[0] + 4 >= json.length()) throw new IllegalArgumentException("bad unicode escape");
                        String hex = json.substring(pos[0]+1, pos[0]+5);
                        sb.append((char) Integer.parseInt(hex, 16));
                        pos[0] += 4;
                        break;
                    default:
                        throw new IllegalArgumentException("invalid escape");
                }
                pos[0]++;
            } else {
                sb.append(c);
                pos[0]++;
            }
        }
        throw new IllegalArgumentException("unterminated string");
    }

    private static Boolean parseBoolean(String json, int[] pos) {
        if (json.startsWith("true", pos[0])) {
            pos[0] += 4;
            return Boolean.TRUE;
        } else if (json.startsWith("false", pos[0])) {
            pos[0] += 5;
            return Boolean.FALSE;
        } else {
            throw new IllegalArgumentException("expected boolean");
        }
    }

    private static void parseNull(String json, int[] pos) {
        if (json.startsWith("null", pos[0])) {
            pos[0] += 4;
        } else {
            throw new IllegalArgumentException("expected null");
        }
    }

    private static void skipWhitespace(String json, int[] pos) {
        while (pos[0] < json.length()) {
            char c = json.charAt(pos[0]);
            if (c == ' ' || c == '\t' || c == '\n' || c == '\r') {
                pos[0]++;
            } else {
                break;
            }
        }
    }
}

