import java.util.*;
import java.io.*;
import java.nio.file.*;

import java.io.IOException;
public class Solution {
    public static String archive_directory(String directory, String dest_tar_path) {
        if (directory == null || dest_tar_path == null) {
            throw new IllegalArgumentException("directory and dest_tar_path must be non-null");
        }
        if (directory.trim().isEmpty() || dest_tar_path.trim().isEmpty()) {
            throw new IllegalArgumentException("inputs must be non-empty");
        }
        if (!dest_tar_path.endsWith(".tar")) {
            throw new IllegalArgumentException("dest_tar_path must end with .tar");
        }

        // Require real directories and normalize paths
        String dir_abs = new File(directory).getAbsolutePath();
        String dest_abs = new File(dest_tar_path).getAbsolutePath();

        if (!new File(dir_abs).isDirectory()) {
            throw new IllegalArgumentException("directory not found");
        }

        // Basic hardening: disallow NUL and newlines in paths
        for (char ch : ("\u0000\n\r").toCharArray()) {
            if (directory.indexOf(ch) != -1 || dest_tar_path.indexOf(ch) != -1) {
                throw new IllegalArgumentException("invalid characters in path");
            }
        }

        // Ensure destination parent directory exists
        String parent = new File(dest_abs).getParent();
        if (parent == null || parent.isEmpty()) {
            parent = ".";
        }
        if (!new File(parent).isDirectory()) {
            throw new IllegalArgumentException("destination directory not found");
        }

        // Collect all entries in the directory (recursively)
        Path dirPath = Paths.get(dir_abs);
        List<String> entries = new ArrayList<>();
        try {
            Files.walk(dirPath).filter(p -> !p.equals(dirPath)).forEach(p -> {
                entries.add(dirPath.relativize(p).toString());
            });
        } catch (IOException e) {
            throw new IllegalArgumentException("Cannot read directory: " + e.getMessage(), e);
        }

        try {
            // Build tar command: tar -cf dest_abs -C dir_abs file1 file2 ...
            List<String> cmd = new ArrayList<>();
            cmd.add("tar");
            cmd.add("-cf");
            cmd.add(dest_abs);
            cmd.add("-C");
            cmd.add(dir_abs);
            cmd.addAll(entries);
            ProcessBuilder pb = new ProcessBuilder(cmd);
            pb.redirectErrorStream(true);
            Process process = pb.start();
            int exitCode = process.waitFor();
            if (exitCode != 0) {
                throw new RuntimeException("tar failed");
            }
        } catch (IOException e) {
            throw new RuntimeException("tar not available", e);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new RuntimeException("tar process interrupted", e);
        }

        return String.format("Archived to %s", dest_abs);
    }
}

