import java.util.*;

public class Solution {
    public static int read_u32_be(byte[] data, int offset) {
        if (data == null) {
            throw new IllegalArgumentException("data must be bytes or bytearray");
        }
        // Use data.length - 4 to avoid integer overflow when offset is near Integer.MAX_VALUE
        if (offset < 0 || offset > data.length - 4) {
            throw new IndexOutOfBoundsException("read out of bounds");
        }

        int b0 = data[offset] & 0xFF;
        int b1 = data[offset + 1] & 0xFF;
        int b2 = data[offset + 2] & 0xFF;
        int b3 = data[offset + 3] & 0xFF;
        return (b0 << 24) | (b1 << 16) | (b2 << 8) | b3;
    }

    public static int readU32Be(byte[] data, int offset) {
        return read_u32_be(data, offset);
    }
}

