import java.util.regex.*;

public class Solution {
    public static String build_redirect_page(String target_url) {
        if (target_url == null) {
            throw new IllegalArgumentException("target_url must not be null");
        }
        String u = target_url.trim();
        if (u.isEmpty()) {
            throw new IllegalArgumentException("target_url must not be empty");
        }

        // No whitespace or common HTML-breaking characters
        if (Pattern.compile("[\\s<>\"']").matcher(u).find()) {
            throw new IllegalArgumentException("target_url contains forbidden characters");
        }

