        try {
            parsed = new java.net.URL(u);
        } catch (java.net.MalformedURLException e) {
            throw new IllegalArgumentException("Invalid URL format");
        }
        String scheme = parsed.getProtocol();
        if (!scheme.equals("http") && !scheme.equals("https")) {
            throw new IllegalArgumentException("Only http and https schemes are allowed");
        }
        String host = parsed.getHost();
        if (host == null || host.isEmpty()) {
            throw new IllegalArgumentException("URL must contain a host");
        }

        String safe_u = u.replace("&", "&amp;")
                         .replace("<", "&lt;")
                         .replace(">", "&gt;")
                         .replace("\"", "&quot;")
                         .replace("'", "&#x27;");
        return "<html><head><meta http-equiv=\"refresh\" content=\"0;url=" + safe_u +
               "\"></head><body>Go to <a href=\"" + safe_u + "\">" + safe_u +
               "</a></body></html>";
