import java.util.*;
import java.util.stream.Collectors;

public class Solution {
    public static String render_marked_search_results(String query, Object results) {
        if (!(query instanceof String)) {
            throw new IllegalArgumentException("query must be a string");
        }
        if (!(results instanceof List)) {
            throw new IllegalArgumentException("results must be a list");
        }

        List<?> resultList = (List<?>) results;
        String safeQuery = escapeHtml(query);

        List<String> safeItems = new ArrayList<>();
        for (Object t : resultList) {
            if (!(t instanceof String)) {
                throw new IllegalArgumentException("each result title must be a string");
            }
            safeItems.add("<li>" + escapeHtml((String) t) + "</li>");
        }

        return "<div class=\"q\">Results for: <span class=\"query\">" + safeQuery +
               "</span></div><ul>" + String.join("", safeItems) + "</ul>";
    }

    private static String escapeHtml(String input) {
        StringBuilder out = new StringBuilder();
        for (int i = 0; i < input.length(); i++) {
            char c = input.charAt(i);
            switch (c) {
                case '&': out.append("&amp;"); break;
                case '<': out.append("&lt;"); break;
                case '>': out.append("&gt;"); break;
                case '"': out.append("&quot;"); break;
                case '\'': out.append("&#x27;"); break;
                default: out.append(c);
            }
        }
        return out.toString();
    }
}

